<?php
declare(strict_types=1);
function ea_enabled():bool{return app_setting('booking_engine','native')==='easyappointments'&&app_setting('easyappointments_url')!==''&&app_setting('easyappointments_api_token_enc')!=='';}
function ea_request(string $method,string $resource,array $query=[],?array $body=null):array{$base=rtrim(app_setting('easyappointments_url'),'/');$token=decrypt_secret(app_setting('easyappointments_api_token_enc'));if($base===''||$token==='')throw new RuntimeException('Easy!Appointments is not configured.');$url=$base.'/index.php/api/v1/'.ltrim($resource,'/');if($query)$url.='?'.http_build_query($query);$ch=curl_init($url);$headers=['Authorization: Bearer '.$token,'Accept: application/json'];$options=[CURLOPT_CUSTOMREQUEST=>$method,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>30,CURLOPT_HTTPHEADER=>$headers];if($body!==null){$headers[]='Content-Type: application/json';$options[CURLOPT_HTTPHEADER]=$headers;$options[CURLOPT_POSTFIELDS]=json_encode($body,JSON_UNESCAPED_SLASHES);}curl_setopt_array($ch,$options);$raw=curl_exec($ch);$status=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);$error=curl_error($ch);curl_close($ch);$data=json_decode((string)$raw,true);if($status<200||$status>=300)throw new RuntimeException('Easy!Appointments API request failed ('.$status.'): '.mb_strimwidth((string)($data['message']??$error?:$raw),0,300,'…'));return is_array($data)?$data:[];}
function ea_availability(array $type,string $date):array{if(!$type['external_provider_id']||!$type['external_service_id'])return [];return ea_request('GET','availabilities',['providerId'=>$type['external_provider_id'],'serviceId'=>$type['external_service_id'],'date'=>$date]);}
function ea_customer(string $name,string $email,string $phone=''):int{$matches=ea_request('GET','customers',['q'=>$email,'length'=>20]);foreach($matches as $customer)if(strtolower((string)($customer['email']??''))===strtolower($email))return (int)$customer['id'];$parts=preg_split('/\s+/',$name,2);$created=ea_request('POST','customers',[],['firstName'=>$parts[0],'lastName'=>$parts[1]??'Booking','email'=>$email,'phone'=>$phone,'address'=>'','city'=>'','zip'=>'','notes'=>'Created by OpenCRM']);return (int)($created['id']??0);}
function ea_create_appointment(array $type,string $name,string $email,string $phone,DateTimeImmutable $start,DateTimeImmutable $end):int{$customerId=ea_customer($name,$email,$phone);if(!$customerId)throw new RuntimeException('Easy!Appointments did not return a customer ID.');$created=ea_request('POST','appointments',[],['start'=>$start->format('Y-m-d H:i:s'),'end'=>$end->format('Y-m-d H:i:s'),'location'=>(string)$type['location_details'],'notes'=>'Booked through OpenCRM','serviceId'=>(int)$type['external_service_id'],'providerId'=>(int)$type['external_provider_id'],'customerId'=>$customerId]);return (int)($created['id']??0);}
